const items = $input.all();
const out = [];
const fmt = (v) => (v == null || v === '') ? 'unknown' : String(v);
for (const it of items) {
  const r = it.json || {};
  const text =
    'Project: ' + fmt(r.project_name) + '\n' +
    'Type: ' + fmt(r.project_type) + ', region=' + fmt(r.region) + ', state=' + fmt(r.state) + ', stage=' + fmt(r.timeline_stage) + '\n' +
    'Earthworks: ' + fmt(r.est_earthworks_cu_yd) + ' cubic yards, site acres=' + fmt(r.site_acres) + ', capex=' + fmt(r.capex_est) + ' USD\n' +
    'Owner company: ' + fmt(r.owner_company) + ' (industry=' + fmt(r.industry) + ', HQ=' + fmt(r.hq_location) + ', size=' + fmt(r.company_size) + ')\n' +
    'Contact: ' + fmt(r.contact_name) + ' - ' + fmt(r.contact_title) + ' (persona=' + fmt(r.persona) + ')';
  out.push({ json: { lead_id: r.lead_id, input_text: text } });
}
return out;
